---


Author Name: **Jie Xu** (@jiexu)
Original Redmine Message: 1447 from https://www.veripool.org



---

For the given verilog code, Verilator generates correct but inefficient code:
```
// change these two parameters to see the speed differences
`define DATA_WIDTH 32
`define REP_COUNT `DATA_WIDTH/4

module t (/*AUTOARG*/
    // Inputs
    clk
    );
    input clk;
    reg [3:0] count = 0;

    reg [`DATA_WIDTH-1:0] a = {`REP_COUNT{4'b0000}};
    reg [`DATA_WIDTH-1:0] b = {`REP_COUNT{4'b1111}};
    reg [`DATA_WIDTH-1:0] res;

    drv t_drv [`DATA_WIDTH-1:0] (.colSelA(a), .colSelB(b), .datao(res));

    always@(posedge clk)
    begin
        count <= count + 1;
        a = {`REP_COUNT{count}};
        b = {`REP_COUNT{count}};

        if (res != (a & b)) begin
            $stop;
        end

        if (count > 10) begin
            $write("*-* All Finished *-*\n");
            $finish;
        end
    end
endmodule

module drv (input colSelA, input colSelB, output datao);
    assign datao = colSelB & colSelA;
endmodule

```

Verilator generates code like this:
```
     vlTOPp->v__DOT__res = ((0x7fffffffU & vlTOPp->v__DOT__res)
                | (0x80000000U & (vlTOPp->v__DOT__b
                          & vlTOPp->v__DOT__a)));
     vlTOPp->v__DOT__res = ((0xbfffffffU & vlTOPp->v__DOT__res)
                | (0x40000000U & (vlTOPp->v__DOT__b
                          & vlTOPp->v__DOT__a)));
     vlTOPp->v__DOT__res = ((0xdfffffffU & vlTOPp->v__DOT__res)
                | (0x20000000U & (vlTOPp->v__DOT__b
                          & vlTOPp->v__DOT__a)));
     vlTOPp->v__DOT__res = ((0xefffffffU & vlTOPp->v__DOT__res)
                | (0x10000000U & (vlTOPp->v__DOT__b
                          & vlTOPp->v__DOT__a)));
     vlTOPp->v__DOT__res = ((0xf7ffffffU & vlTOPp->v__DOT__res)
                | (0x8000000U & (vlTOPp->v__DOT__b
                         & vlTOPp->v__DOT__a)));
     vlTOPp->v__DOT__res = ((0xfbffffffU & vlTOPp->v__DOT__res)
                | (0x4000000U & (vlTOPp->v__DOT__b
                         & vlTOPp->v__DOT__a)));
     vlTOPp->v__DOT__res = ((0xfdffffffU & vlTOPp->v__DOT__res)
                | (0x2000000U & (vlTOPp->v__DOT__b
                         & vlTOPp->v__DOT__a)));

```
which should basically replaced by 
```
vlTOPp->v__DOT__res = (vlTOPp->v__DOT__b & vlTOPp->v__DOT__a)

```

